// ── State ─────────────────────────────────────────────────────────────────────
let pr_mode         = 'count';
let pr_display      = 'array';    // 'array' | 'frame' | 'clustered'
let pr_align        = 'left';     // 'left' | 'centre'  (array only)
let pr_countA       = 7;
let pr_imageA       = 'illus:space/crescent_moon_yellow';    // imageId: plain string (emoji), 'counter:S:F:C', 'illus:path'
let pr_countB       = 3;
let pr_imageB       = 'illus:space/crescent_moon_yellow';
let pr_op           = 'add';
let pr_subMode      = 'crossed';  // 'total' | 'separate' | 'crossed'
let pr_cols         = 5;
let pr_mrows        = 2;
let pr_mcols        = 5;
let pr_illusOutline = true;       // show circle outline under illustrations
let pr_imgScale    = 1.0;         // image scale multiplier (1.0 = default)
let pr_numA        = false;       // show Group A as a numeral instead of images
let pr_numB        = false;       // show Group B as a numeral instead of images
let pr_showEq      = false;       // show = sign after Group B in addsub
// Image bank UI state
let pr_bankA        = 'illus';    // 'emoji' | 'counter' | 'illus'
let pr_bankB        = 'illus';
let pr_bankGroupSel = 'A';        // which group's bank is displayed
// Counter sub-state (shape, face, colour indices)
let pr_counterA     = {s:0, f:0, c:0};
let pr_counterB     = {s:1, f:2, c:3};

function prClamp(v, mn, mx) { return Math.max(mn, Math.min(mx, Math.round(+v) || mn)); }

// ── Counter: random selection ─────────────────────────────────────────────────
function prRandomCounter() {
  return {
    s: Math.floor(Math.random() * COUNTER_SHAPES.length),
    f: Math.floor(Math.random() * COUNTER_FACES.length),
    c: Math.floor(Math.random() * COUNTER_COLOURS.length),
  };
}

// ── Image Lookup ──────────────────────────────────────────────────────────────
// Returns {type:'emoji'|'counter'|'illus', ...properties}
function lookupImg(imageId) {
  if (!imageId) return {type:'emoji', ...PR_IMAGE_BANK[0]};
  if (imageId.startsWith('counter:')) {
    const p = imageId.split(':');
    return {type:'counter', shapeIdx:+p[1]||0, faceIdx:+p[2]||0, colourIdx:+p[3]||0};
  }
  if (imageId.startsWith('illus:')) {
    const id   = imageId.slice(6);
    const item = ILLUSTRATION_BANK.find(x => x.id === id);
    return item ? {type:'illus', ...item} : {type:'emoji', ...PR_IMAGE_BANK[0]};
  }
  const item = PR_IMAGE_BANK.find(x => x.id === imageId);
  return item ? {type:'emoji', ...item} : {type:'emoji', ...PR_IMAGE_BANK[0]};
}

// ── Counter thumbnail SVG (used in picker and in canvas) ──────────────────────
// Returns an inline SVG string showing a counter at size×size pixels.
function counterSVG(shapeIdx, faceIdx, colourIdx, size) {
  const shape  = COUNTER_SHAPES[shapeIdx] || COUNTER_SHAPES[0];
  const face   = faceIdx >= 0 ? (COUNTER_FACES[faceIdx] || COUNTER_FACES[0]) : [];
  const colour = COUNTER_COLOURS[colourIdx] || COUNTER_COLOURS[0];
  const sp = shape.paths.map(p => `<path d="${p}" fill="${colour}"/>`).join('');
  const yOff = faceIdx >= 0 ? (COUNTER_FACE_OFFSETS[faceIdx] || 0) : 0;
  const facePaths = face.map(p => `<path d="${p.d}" fill="${p.f}"/>`).join('');
  const fp = yOff ? `<g transform="translate(0,${yOff})">${facePaths}</g>` : facePaths;
  // Expanded viewBox gives breathing room for faces/shapes that exceed the
  // 0-100 box (hair, star tips). No clip — shapes are their own silhouette.
  return `<svg viewBox="-15 -15 130 130" width="${size}" height="${size}" xmlns="http://www.w3.org/2000/svg">${sp}${fp}</svg>`;
}

// ── Image Bank UI ─────────────────────────────────────────────────────────────
function prBankSetGroup(btn) {
  pr_bankGroupSel = btn.dataset.grp;
  document.querySelectorAll('[data-grp]').forEach(b =>
    b.classList.toggle('active', b.dataset.grp === pr_bankGroupSel));
  const tab = pr_bankGroupSel === 'A' ? pr_bankA : pr_bankB;
  document.querySelectorAll('[data-banktab]').forEach(b =>
    b.classList.toggle('active', b.dataset.banktab === tab));
  prBankRender();
  autoPreviewPR();
}

function prBankSetTab(btn) {
  const tab = btn.dataset.banktab;
  // Tab change applies to BOTH groups so they stay in sync
  pr_bankA = tab;
  pr_bankB = tab;
  document.querySelectorAll('[data-banktab]').forEach(b =>
    b.classList.toggle('active', b.dataset.banktab === tab));

  if (tab === 'counter') {
    // Give Group A a counter if it doesn't already have one
    if (!pr_imageA.startsWith('counter:')) {
      const r = prRandomCounter();
      pr_counterA = r;
      pr_imageA = `counter:${r.s}:${r.f}:${r.c}`;
    }
    // Mirror to Group B if B doesn't already have a counter
    if (!pr_imageB.startsWith('counter:')) {
      pr_counterB = {...pr_counterA};
      pr_imageB = pr_imageA;
    }
  } else if (tab === 'illus') {
    if (!pr_imageA.startsWith('illus:') && ILLUSTRATION_BANK.length) {
      pr_imageA = `illus:${ILLUSTRATION_BANK[0].id}`;
    }
    if (!pr_imageB.startsWith('illus:')) {
      pr_imageB = pr_imageA; // mirror A
    }
  } else { // emoji
    if (pr_imageA.startsWith('counter:') || pr_imageA.startsWith('illus:')) {
      pr_imageA = PR_IMAGE_BANK[0]?.id || 'tiger';
    }
    if (pr_imageB.startsWith('counter:') || pr_imageB.startsWith('illus:')) {
      pr_imageB = pr_imageA; // mirror A
    }
  }
  prBankRender();
  prUpdateGroupThumbs();
  autoPreviewPR();
}

// Sync pr_counterA/B from imageId strings
function prSyncCounterState() {
  if (pr_imageA.startsWith('counter:')) {
    const p = pr_imageA.split(':');
    pr_counterA = {s:+p[1]||0, f:+p[2]||0, c:+p[3]||0};
  }
  if (pr_imageB.startsWith('counter:')) {
    const p = pr_imageB.split(':');
    pr_counterB = {s:+p[1]||0, f:+p[2]||0, c:+p[3]||0};
  }
}

function prBankRender() {
  const el = document.getElementById('pr-bank-content');
  if (!el) return;
  const isB   = pr_bankGroupSel === 'B';
  const tab   = isB ? pr_bankB : pr_bankA;
  const selId = isB ? pr_imageB : pr_imageA;
  const fn    = isB ? 'prBankSelB' : 'prBankSelA';

  if (tab === 'emoji') {
    el.innerHTML = PR_IMAGE_BANK.map(img => {
      const sel = selId === img.id;
      return `<button class="pr-img-btn${sel ? ' selected' : ''}"
        title="${img.label}" onclick="${fn}('${img.id}')"
        style="width:46px;height:46px;background:${img.bg};border-color:${sel ? img.stroke : 'transparent'}">
        <span style="font-size:22px;line-height:1;display:block">${img.emoji}</span>
      </button>`;
    }).join('');

  } else if (tab === 'counter') {
    const cs = isB ? pr_counterB : pr_counterA;
    const upd = `prCounterPick('${isB?'B':'A'}','PART',IDX)`;

    // ── Shape row ──────────────────────────────────────────────────────────
    const shapeHTML = COUNTER_SHAPES.map((sh, i) => {
      const sel = cs.s === i;
      const svg = counterSVG(i, cs.f, cs.c, 44);
      return `<button class="pr-img-btn${sel?' selected':''}" title="${sh.name}"
        onclick="prCounterPick('${isB?'B':'A'}','s',${i})"
        style="width:50px;height:50px;padding:2px;border-color:${sel?'#333':'transparent'}">
        ${svg}
      </button>`;
    }).join('');

    // ── Face row ──────────────────────────────────────────────────────────
    const noFaceSel = cs.f === -1;
    const noFaceBtn = `<button class="pr-img-btn${noFaceSel?' selected':''}" title="No expression"
      onclick="prCounterPick('${isB?'B':'A'}','f',-1)"
      style="width:50px;height:50px;padding:2px;border-color:${noFaceSel?'#333':'transparent'}">
      ${counterSVG(cs.s, -1, cs.c, 44)}
    </button>`;
    const faceHTML = noFaceBtn + COUNTER_FACES.map((_, i) => {
      const sel = cs.f === i;
      const svg = counterSVG(cs.s, i, cs.c, 44);
      return `<button class="pr-img-btn${sel?' selected':''}" title="Expression ${i+1}"
        onclick="prCounterPick('${isB?'B':'A'}','f',${i})"
        style="width:50px;height:50px;padding:2px;border-color:${sel?'#333':'transparent'}">
        ${svg}
      </button>`;
    }).join('');

    // ── Colour swatches ───────────────────────────────────────────────────
    const colHTML = COUNTER_COLOURS.map((c, i) => {
      const sel = cs.c === i;
      return `<button onclick="prCounterPick('${isB?'B':'A'}','c',${i})"
        title="${COUNTER_COLOUR_NAMES[i]}"
        style="width:28px;height:28px;border-radius:50%;background:${c};border:${sel?'3px solid #333':'2px solid rgba(0,0,0,0.15)'};cursor:pointer;flex-shrink:0"></button>`;
    }).join('');

    const labelStyle = 'font-size:10px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:.4px;margin-bottom:4px';
    el.innerHTML = `
      <div style="${labelStyle}">Colour</div>
      <div style="display:flex;gap:5px;flex-wrap:wrap;margin-bottom:8px">${colHTML}</div>
      <div style="${labelStyle}">Shape</div>
      <div style="display:flex;flex-wrap:wrap;gap:4px;margin-bottom:8px">${shapeHTML}</div>
      <div style="${labelStyle}">Expression</div>
      <div style="display:flex;flex-wrap:wrap;gap:4px">${faceHTML}</div>`;

  } else {
    // Illustrations
    el.innerHTML = ILLUSTRATION_BANK.map(img => {
      const iid = `illus:${img.id}`;
      const sel = selId === iid;
      const url = `${ILLUS_BASE}/${img.id}.png`;
      return `<button class="pr-img-btn${sel ? ' selected' : ''}"
        title="${img.label}" onclick="${fn}('illus:${img.id}')"
        style="width:52px;height:52px;padding:2px;background:#f4f5f6;border-color:${sel ? '#555' : 'transparent'};border-width:${sel ? 2 : 1}px;border-style:solid">
        <img src="${url}" width="46" height="46"
             style="object-fit:contain;display:block;margin:0 auto">
      </button>`;
    }).join('');
  }
}

function prCounterPick(grp, part, idx) {
  const isB = grp === 'B';
  const cs = isB ? pr_counterB : pr_counterA;
  cs[part] = idx;
  const id = `counter:${cs.s}:${cs.f}:${cs.c}`;
  if (isB) pr_imageB = id; else pr_imageA = id;
  prBankRender();
  prUpdateGroupThumbs();
  autoPreviewPR();
}

function prBankSelA(id) {
  pr_imageA = id;
  if (pr_bankGroupSel === 'A') prBankRender();
  prUpdateGroupThumbs();
  autoPreviewPR();
}
function prBankSelB(id) {
  pr_imageB = id;
  if (pr_bankGroupSel === 'B') prBankRender();
  prUpdateGroupThumbs();
  autoPreviewPR();
}

// Render mini image thumbnails next to Group A / B labels in addsub area
function prUpdateGroupThumbs() {
  function thumbHTML(id) {
    if (id && id.startsWith('counter:')) {
      const p = id.split(':');
      return counterSVG(+p[1]||0, +p[2]||0, +p[3]||0, 30);
    } else if (id && id.startsWith('illus:')) {
      const url = `${ILLUS_BASE}/${id.slice(6)}.png`;
      return `<div style="width:30px;height:30px;border-radius:50%;overflow:hidden;background:#f0f0f0"><img src="${url}" width="30" height="30" style="object-fit:cover;width:100%;height:100%"></div>`;
    } else {
      const img = PR_IMAGE_BANK.find(x => x.id === id) || PR_IMAGE_BANK[0];
      return `<div style="width:30px;height:30px;border-radius:50%;background:${img.bg};border:2px solid ${img.stroke};display:flex;align-items:center;justify-content:center;font-size:17px;line-height:1">${img.emoji}</div>`;
    }
  }
  const ta = document.getElementById('pr-thumb-a');
  if (ta) ta.innerHTML = thumbHTML(pr_imageA);
  const tb = document.getElementById('pr-thumb-b');
  if (tb) tb.innerHTML = thumbHTML(pr_imageB);
}

// Click a thumbnail to switch the bank panel to that group
function prBankActivateGroup(grp) {
  const btn = document.querySelector(`[data-grp="${grp}"]`);
  if (btn) prBankSetGroup(btn);
  const bp = document.getElementById('pr-bank-panel');
  if (bp) bp.scrollIntoView({behavior:'smooth', block:'nearest'});
}

