// ── Init ──────────────────────────────────────────────────────────────────────
function initPRPanel() {
  prBankRender();
  prUpdateMode();
  autoPreviewPR();
}

function prSetMode(btn) {
  pr_mode = btn.dataset.prmode;
  document.querySelectorAll('[data-prmode]').forEach(b =>
    b.classList.toggle('active', b.dataset.prmode === pr_mode));
  // Seed Group B from Group A when first entering addsub (B still at default 'apple')
  if (pr_mode === 'addsub' && pr_imageB === 'illus:space/crescent_moon_yellow') {
    pr_imageB   = pr_imageA;
    pr_bankB    = pr_bankA;
    pr_counterB = {...pr_counterA};
  }
  pr_bankGroupSel = 'A';
  document.querySelectorAll('[data-grp]').forEach(b =>
    b.classList.toggle('active', b.dataset.grp === 'A'));
  const tab = pr_bankA;
  document.querySelectorAll('[data-banktab]').forEach(b =>
    b.classList.toggle('active', b.dataset.banktab === tab));
  prBankRender();
  prUpdateMode();
  autoPreviewPR();
}

function prUpdateMode() {
  const isMultiply = pr_mode === 'multiply';
  const isAddSub   = pr_mode === 'addsub';
  const show = (id, v) => { const e = document.getElementById(id); if (e) e.style.display = v ? '' : 'none'; };
  show('pr-count-wrap',     pr_mode === 'count');
  show('pr-addsub-wrap',    isAddSub);
  show('pr-multiply-wrap',  isMultiply);
  show('pr-layout-row',     !isMultiply);
  show('pr-bank-group-sel', isAddSub);
  const isArray = pr_display === 'array' && !isMultiply;
  show('pr-cols-field',  isArray);
  show('pr-align-field', isArray);
  // Show outline toggle whenever any illustration is in use or selected in bank
  const hasIllus = pr_imageA.startsWith('illus:') || pr_imageB.startsWith('illus:')
                || pr_bankA === 'illus' || pr_bankB === 'illus';
  show('pr-illus-opts', hasIllus);
  if (isAddSub) prUpdateSubUI();
}

function prSetDisplay(btn) {
  pr_display = btn.dataset.prd;
  document.querySelectorAll('[data-prd]').forEach(b =>
    b.classList.toggle('active', b.dataset.prd === pr_display));
  const isArray = pr_display === 'array' && pr_mode !== 'multiply';
  const showEl = (id, v) => { const e = document.getElementById(id); if (e) e.style.display = v ? '' : 'none'; };
  showEl('pr-cols-field',  isArray);
  showEl('pr-align-field', isArray);
  autoPreviewPR();
}

function prSetAlign(btn) {
  pr_align = btn.dataset.pralign;
  document.querySelectorAll('[data-pralign]').forEach(b =>
    b.classList.toggle('active', b.dataset.pralign === pr_align));
  autoPreviewPR();
}

function prSetOp(btn) {
  pr_op = btn.dataset.prop;
  document.querySelectorAll('[data-prop]').forEach(b =>
    b.classList.toggle('active', b.dataset.prop === pr_op));
  prUpdateSubUI();
  autoPreviewPR();
}

function prSetSubMode(btn) {
  pr_subMode = btn.dataset.prsub;
  document.querySelectorAll('[data-prsub]').forEach(b =>
    b.classList.toggle('active', b.dataset.prsub === pr_subMode));
  prUpdateSubUI();
  autoPreviewPR();
}

function prUpdateSubUI() {
  const isSub = pr_op === 'sub';
  const subRow = document.getElementById('pr-submode-row');
  if (subRow) {
    subRow.style.opacity = isSub ? '1' : '0.4';
    subRow.style.pointerEvents = isSub ? '' : 'none';
  }
  const showBankB = !isSub || pr_subMode === 'separate';
  const grpB = document.getElementById('pr-groupb-wrap');
  if (grpB) { grpB.style.opacity = showBankB ? '1' : '0.4'; grpB.style.pointerEvents = showBankB ? '' : 'none'; }
  const lblA = document.getElementById('pr-label-a');
  const lblB = document.getElementById('pr-label-b');
  if (isSub) {
    if (lblA) lblA.textContent = 'Total (minuend)';
    if (lblB) lblB.textContent = pr_subMode === 'total'   ? 'Take away (not shown)' :
                                 pr_subMode === 'crossed' ? 'Cross out — how many'  : 'Take away';
  } else {
    if (lblA) lblA.textContent = 'Group A';
    if (lblB) lblB.textContent = 'Group B';
  }
}

function prDelta(grp, d) {
  if (grp === 'A') {
    pr_countA = prClamp(pr_countA + d, 1, 20);
    ['pr-ca', 'pr-addsub-ca'].forEach(id => { const e = document.getElementById(id); if (e) e.value = pr_countA; });
  } else {
    pr_countB = prClamp(pr_countB + d, 1, 20);
    const e = document.getElementById('pr-addsub-cb'); if (e) e.value = pr_countB;
  }
  autoPreviewPR();
}

function prDeltaMul(dim, d) {
  if (dim === 'rows') { pr_mrows = prClamp(pr_mrows + d, 1, 10); const e = document.getElementById('pr-mrows'); if (e) e.value = pr_mrows; }
  else               { pr_mcols = prClamp(pr_mcols + d, 1, 10); const e = document.getElementById('pr-mcols'); if (e) e.value = pr_mcols; }
  autoPreviewPR();
}

function prDeltaCols(d) {
  pr_cols = prClamp(pr_cols + d, 1, 10);
  const e = document.getElementById('pr-cols-in'); if (e) e.value = pr_cols;
  autoPreviewPR();
}

function autoPreviewPR() {
  const box = document.getElementById('pr-preview');
  if (!box) return;
  // Show outline toggle whenever any illustration is in use or selected in the bank
  const hasIllus = pr_imageA.startsWith('illus:') || pr_imageB.startsWith('illus:')
                || pr_bankA === 'illus' || pr_bankB === 'illus';
  const optsEl = document.getElementById('pr-illus-opts');
  if (optsEl) optsEl.style.display = hasIllus ? '' : 'none';
  prUpdateGroupThumbs();
  // Reflect alignment in the preview container — frame mode always centres
  box.style.justifyContent = (pr_align === 'left' && pr_display !== 'frame') ? 'flex-start' : 'center';
  try {
    box.innerHTML = pictorialSVG(getPRConfig());
  } catch (err) {
    console.error('PR preview error:', err);
    box.innerHTML = '<p class="preview-empty">Preview error — see console.</p>';
  }
}

function getPRConfig() {
  return {
    mode:         pr_mode,
    display:      pr_display,
    align:        pr_align,
    countA:       pr_countA,
    imageIdA:     pr_imageA,
    countB:       pr_countB,
    imageIdB:     pr_imageB,
    op:           pr_op,
    subMode:      pr_subMode,
    cols:         pr_cols,
    mrows:        pr_mrows,
    mcols:        pr_mcols,
    illusOutline: pr_illusOutline,
    imgScale:     pr_imgScale,
    numA:         pr_numA,
    numB:         pr_numB,
    showEq:       pr_showEq,
  };
}

function restorePRConfig(cfg) {
  if (!cfg) return;
  pr_mode         = cfg.mode         || 'count';
  pr_display      = cfg.display      || 'array';
  pr_align        = cfg.align        || 'left';
  pr_countA       = cfg.countA       || 7;
  pr_imageA       = cfg.imageIdA     || 'illus:space/crescent_moon_yellow';
  pr_countB       = cfg.countB       || 3;
  pr_imageB       = cfg.imageIdB     || 'illus:space/crescent_moon_yellow';
  pr_op           = cfg.op           || 'add';
  pr_subMode      = cfg.subMode      || 'crossed';
  pr_cols         = cfg.cols         || 5;
  pr_mrows        = cfg.mrows        || 2;
  pr_mcols        = cfg.mcols        || 5;
  pr_illusOutline = cfg.illusOutline !== false;
  pr_imgScale     = cfg.imgScale ?? 1.0;
  pr_numA         = !!cfg.numA;
  pr_numB         = !!cfg.numB;
  pr_showEq       = !!cfg.showEq;
  const typeA = pr_imageA.startsWith('counter:') ? 'counter' : pr_imageA.startsWith('illus:') ? 'illus' : 'emoji';
  const typeB = pr_imageB.startsWith('counter:') ? 'counter' : pr_imageB.startsWith('illus:') ? 'illus' : 'emoji';
  pr_bankA = typeA; pr_bankB = typeB;
  pr_bankGroupSel = 'A';
  prSyncCounterState();
  const sv = (id, v) => { const e = document.getElementById(id); if (e) e.value = v; };
  sv('pr-ca', pr_countA);       sv('pr-addsub-ca', pr_countA);
  sv('pr-addsub-cb', pr_countB);
  sv('pr-mrows', pr_mrows);     sv('pr-mcols', pr_mcols);
  sv('pr-cols-in', pr_cols);
  sv('pr-img-scale', pr_imgScale);
  const scaleVal = document.getElementById('pr-img-scale-val');
  if (scaleVal) scaleVal.textContent = Math.round(pr_imgScale * 100) + '%';
  const sc = (id, v) => { const e = document.getElementById(id); if (e) e.checked = v; };
  sc('pr-illus-outline', pr_illusOutline);
  sc('pr-num-a',   pr_numA);
  sc('pr-num-b',   pr_numB);
  sc('pr-show-eq', pr_showEq);
  document.querySelectorAll('[data-prmode]').forEach(b => b.classList.toggle('active', b.dataset.prmode === pr_mode));
  document.querySelectorAll('[data-prd]').forEach(b => b.classList.toggle('active', b.dataset.prd === pr_display));
  document.querySelectorAll('[data-pralign]').forEach(b => b.classList.toggle('active', b.dataset.pralign === pr_align));
  document.querySelectorAll('[data-prop]').forEach(b => b.classList.toggle('active', b.dataset.prop === pr_op));
  document.querySelectorAll('[data-prsub]').forEach(b => b.classList.toggle('active', b.dataset.prsub === pr_subMode));
  document.querySelectorAll('[data-banktab]').forEach(b => b.classList.toggle('active', b.dataset.banktab === pr_bankA));
  document.querySelectorAll('[data-grp]').forEach(b => b.classList.toggle('active', b.dataset.grp === 'A'));
  prBankRender();
  prUpdateMode();
  prUpdateSubUI();
  autoPreviewPR();
}

function prResetState() {
  pr_mode = 'count'; pr_display = 'array'; pr_align = 'left';
  pr_countA = 7; pr_imageA = 'illus:space/crescent_moon_yellow';
  pr_countB = 3; pr_imageB = 'illus:space/crescent_moon_yellow';
  pr_op = 'add'; pr_subMode = 'crossed';
  pr_cols = 5; pr_mrows = 2; pr_mcols = 5;
  pr_illusOutline = true;
  pr_numA = false; pr_numB = false; pr_showEq = false;
  pr_bankA = 'illus'; pr_bankB = 'illus'; pr_bankGroupSel = 'A';
  pr_counterA = {s:0, f:0, c:0}; pr_counterB = {s:1, f:2, c:3};
}

// ── SVG Renderer ──────────────────────────────────────────────────────────────
function pictorialSVG(cfg) {
  const {
    mode        = 'count',
    display     = 'array',
    align       = 'left',
    countA      = 7,  imageIdA = 'tiger',
    countB      = 3,  imageIdB = 'apple',
    op          = 'add',
    subMode     = 'crossed',
    cols        = 5,
    mrows       = 2,  mcols = 5,
    illusOutline = true,
    imgScale = 1.0,
    numA    = false,
    numB    = false,
    showEq  = false,
  } = cfg;

  const R    = 22 * imgScale;
  const GAP  = 10 * imgScale;
  const PAD  = 22 * imgScale;
  const S    = R * 2 + GAP;
  const HX   = S;
  const HY   = HX * (Math.sqrt(3) / 2);
  const FONT = "'Proxima Soft','Nunito',sans-serif";

  const imgA = lookupImg(imageIdA);
  const imgB = lookupImg(imageIdB);

  const esc = s => String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const defs = [];
  let _uid = 0;
  const uid = () => `u${_uid++}`;

  // ── Single item renderer ──────────────────────────────────────────────────
  // r: optional radius override (used by renderFrames for larger frame cells)
  function renderItem(img, cx, cy, crossed, r) {
    const IR = (r !== undefined) ? r : R;
    let s = '';

    if (img.type === 'counter') {
      // Shapes are their own silhouette — no circle clip.
      // Scale 100×100 normalised space → 2IR×2IR, centred at (cx, cy).
      const {shapeIdx, faceIdx, colourIdx} = img;
      const shape  = COUNTER_SHAPES[shapeIdx] || COUNTER_SHAPES[0];
      const face   = faceIdx >= 0 ? (COUNTER_FACES[faceIdx] || COUNTER_FACES[0]) : [];
      const colour = COUNTER_COLOURS[colourIdx] || COUNTER_COLOURS[0];
      const sc = (IR * 2) / 100;
      s += `<g transform="translate(${cx - IR},${cy - IR}) scale(${sc})">`;
      shape.paths.forEach(p => { s += `<path d="${p}" fill="${colour}"/>`; });
      if (face.length) {
        const faceYOff = COUNTER_FACE_OFFSETS[faceIdx] || 0;
        if (faceYOff) s += `<g transform="translate(0,${faceYOff})">`;
        face.forEach(p => { s += `<path d="${p.d}" fill="${p.f}"/>`; });
        if (faceYOff) s += '</g>';
      }
      s += '</g>';

    } else if (img.type === 'illus') {
      const url = `${ILLUS_BASE}/${img.id}.png`;
      const ar  = img.ar || 1;
      // Without the circle clip there's nothing to trim corners, so scale up a bit
      const T    = illusOutline ? 0.88 : 1.1;
      const ISCL = ar >= 1
        ? T / Math.sqrt(1 + 1 / (ar * ar))
        : T / Math.sqrt(ar * ar + 1);
      const iw  = (ar >= 1 ? IR*2 : IR*2*ar) * ISCL;
      const ih  = (ar >= 1 ? IR*2/ar : IR*2) * ISCL;
      const idx = img.dx || 0;
      const idy = img.dy || 0;
      const ix  = cx - (0.5 + idx) * iw;
      const iy  = cy - (0.5 + idy) * ih;
      if (illusOutline) {
        s += `<circle cx="${cx}" cy="${cy}" r="${IR}" fill="#fff" stroke="#D1D5DB" stroke-width="2"/>`;
        const id = uid();
        defs.push(`<clipPath id="${id}"><circle cx="${cx}" cy="${cy}" r="${IR}"/></clipPath>`);
        s += `<image x="${ix}" y="${iy}" width="${iw}" height="${ih}" href="${url}" clip-path="url(#${id})" preserveAspectRatio="none"/>`;
      } else {
        s += `<image x="${ix}" y="${iy}" width="${iw}" height="${ih}" href="${url}" preserveAspectRatio="none"/>`;
      }

    } else {
      // Emoji
      const fs = Math.round(IR * 1.05);
      s += `<circle cx="${cx}" cy="${cy}" r="${IR}" fill="${img.bg}" stroke="${img.stroke}" stroke-width="2.5"/>`;
      s += `<text x="${cx}" y="${cy}" dominant-baseline="central" text-anchor="middle" font-size="${fs}" font-family="sans-serif">${esc(img.emoji)}</text>`;
    }

    if (crossed) {
      const d = IR * 0.60, sw = Math.max(2.5, IR * 0.12);
      s += `<line x1="${cx - d}" y1="${cy - d}" x2="${cx + d}" y2="${cy + d}" stroke="#DC2626" stroke-width="${sw}" stroke-linecap="round"/>`;
      s += `<line x1="${cx + d}" y1="${cy - d}" x2="${cx - d}" y2="${cy + d}" stroke="#DC2626" stroke-width="${sw}" stroke-linecap="round"/>`;
    }
    return s;
  }

  // ── Array positions ───────────────────────────────────────────────────────
  // forceLeft: skip the centering offset (used inside renderTwoGroups where the
  // group occupies only part of the canvas and centring would push items into the operator)
  function arrayPts(count, perRow, ox, oy, forceLeft) {
    const partial = count % perRow;
    const lastRowLen = partial === 0 ? perRow : partial;
    const lastRow = Math.floor((count - 1) / perRow);
    return Array.from({length: count}, (_, i) => {
      const col = i % perRow, row = Math.floor(i / perRow);
      const isFinalRow = row === lastRow && lastRowLen < perRow;
      const xOff = (!forceLeft && align === 'centre' && isFinalRow) ? (perRow - lastRowLen) * S / 2 : 0;
      return { x: ox + col * S + R + xOff, y: oy + row * S + R };
    });
  }

  function arrayBox(count, perRow) {
    return { w: perRow * S - GAP, h: Math.ceil(count / perRow) * S - GAP };
  }

  // ── Clustered: hexagonal close-packing ───────────────────────────────────
  function clusterPts(count, ox, oy) {
    if (count === 0) return [];
    const maxRows = count <= 10 ? 2 : 3;
    const cols_c = Math.max(2, Math.ceil(count / maxRows));
    return Array.from({length: count}, (_, i) => {
      const row = Math.floor(i / cols_c), col = i % cols_c;
      return { x: col * HX + (row % 2) * (HX / 2) + ox + R, y: row * HY + oy + R };
    });
  }

  // ── 10-frame renderer ─────────────────────────────────────────────────────
  // Frames are laid out side-by-side (horizontal) when count > 10.
  // FS/RF are larger than the array cell/radius so items have breathing room.
  const F_COLS = 5, F_ROWS = 2;
  const F_PER  = F_COLS * F_ROWS;   // 10 items per frame
  const FS     = 68 * imgScale;      // frame cell size (vs array step S=54)
  const RF     = 26 * imgScale;     // frame item radius (vs array R=22)
  const FW     = F_COLS * FS;       // one frame width  = 340
  const FH     = F_ROWS * FS;       // one frame height = 136

  function renderFrames(count, img, ox, oy, parts, crossFrom) {
    const numFrames = Math.ceil(Math.max(1, count) / F_PER);
    const fGap = 16;
    const GL = 1.5, GC = '#374151', lh = GL / 2;

    for (let f = 0; f < numFrames; f++) {
      const fx = ox + f * (FW + fGap);  // frames side by side
      parts.push(`<rect x="${fx}" y="${oy}" width="${FW}" height="${FH}" fill="#fff"/>`);

      // Items — centred within each cell
      const fStart = f * F_PER, fCount = Math.min(count - fStart, F_PER);
      for (let i = 0; i < fCount; i++) {
        const gi = fStart + i, col = i % F_COLS, row = Math.floor(i / F_COLS);
        const cx = fx + col * FS + FS / 2;
        const cy = oy + row * FS + FS / 2;
        parts.push(renderItem(img, cx, cy, crossFrom !== undefined && gi >= crossFrom, RF));
      }

      // Grid lines on top of items (border + internal dividers)
      const la = `stroke="${GC}" stroke-width="${GL}" stroke-linecap="square"`;
      for (let col = 0; col <= F_COLS; col++) {
        const x = col === 0 ? fx + lh : col === F_COLS ? fx + FW - lh : fx + col * FS;
        parts.push(`<line x1="${x}" y1="${oy + lh}" x2="${x}" y2="${oy + FH - lh}" ${la}/>`);
      }
      for (let row = 0; row <= F_ROWS; row++) {
        const y = row === 0 ? oy + lh : row === F_ROWS ? oy + FH - lh : oy + row * FS;
        parts.push(`<line x1="${fx + lh}" y1="${y}" x2="${fx + FW - lh}" y2="${y}" ${la}/>`);
      }
    }
    return { w: numFrames * (FW + fGap) - fGap, h: FH };
  }

  // ── Render a single group ─────────────────────────────────────────────────
  // forceLeft: passed through to arrayPts to suppress centering offset
  function renderGroup(count, img, ox, oy, parts, crossFrom, forceLeft) {
    if (display === 'frame') {
      return renderFrames(count, img, ox, oy, parts, crossFrom);
    } else if (display === 'clustered') {
      const pts = clusterPts(count, ox, oy);
      const maxX = pts.length ? Math.max(...pts.map(p => p.x + R)) : ox;
      const maxY = pts.length ? Math.max(...pts.map(p => p.y + R)) : oy;
      pts.forEach(({x, y}, i) => parts.push(renderItem(img, x, y, crossFrom !== undefined && i >= crossFrom)));
      return { w: maxX - ox, h: maxY - oy };
    } else {
      const {w, h} = arrayBox(count, cols);
      arrayPts(count, cols, ox, oy, forceLeft).forEach(({x, y}, i) =>
        parts.push(renderItem(img, x, y, crossFrom !== undefined && i >= crossFrom)));
      return { w, h };
    }
  }

  // ── Render two groups side by side ────────────────────────────────────────
  function renderTwoGroups(parts, crossedB) {
    const OP_W = 54;
    const EQ_W = 90;
    const {h: hA} = arrayBox(countA, cols);
    const {h: hB} = arrayBox(countB, cols);
    // Estimate numeral rendered width (px at ≈72px font) so = sits OP_W/2 after numeral
    const numWA = String(countA).length === 1 ? 42 : 75;
    const numWB = String(countB).length === 1 ? 42 : 75;
    let realWA, realHA, realWB, realHB;
    if (display === 'clustered') {
      const ptA = clusterPts(countA, 0, 0);
      realWA = numA ? numWA : (ptA.length ? Math.max(...ptA.map(p => p.x + R)) : S);
      realHA = numA ? S     : (ptA.length ? Math.max(...ptA.map(p => p.y + R)) : S);
      const ptB = clusterPts(countB, 0, 0);
      realWB = numB ? numWB : (ptB.length ? Math.max(...ptB.map(p => p.x + R)) : S);
      realHB = numB ? S     : (ptB.length ? Math.max(...ptB.map(p => p.y + R)) : S);
    } else if (display === 'frame') {
      const fGap = 16;
      const numFA = Math.ceil(Math.max(1, countA) / F_PER);
      const numFB = Math.ceil(Math.max(1, countB) / F_PER);
      // Frames are horizontal: width = numFrames × FW + gaps, height = FH
      realWA = numA ? numWA : numFA * (FW + fGap) - fGap;
      realHA = FH;
      realWB = numB ? numWB : numFB * (FW + fGap) - fGap;
      realHB = FH;
    } else {
      // array: use actual rendered width — min(count, cols) items per row, not the full cols
      realWA = numA ? numWA : Math.min(Math.max(1, countA), cols) * S - GAP;
      realHA = numA ? S     : hA;
      realWB = numB ? numWB : Math.min(Math.max(1, countB), cols) * S - GAP;
      realHB = numB ? S     : hB;
    }
    const maxH = Math.max(realHA, realHB);
    const svgW = PAD + realWA + OP_W + realWB + (showEq ? EQ_W : 0) + PAD;
    const svgH = maxH + PAD * 2;

    // Operator / numerals align with the top row of whichever group has images.
    // For frame cells the first-row centre is FS/2; for array/clustered it's R.
    const opY = PAD + (display === 'frame' ? FS / 2 : R);
    const fs  = Math.min(72, maxH * 0.85);

    // Group A — top-aligned
    if (numA) {
      parts.push(`<text x="${PAD + realWA / 2}" y="${opY}" dominant-baseline="central" text-anchor="middle" font-size="${fs}" font-weight="700" font-family="${FONT}" fill="#1F2937">${countA}</text>`);
    } else {
      renderGroup(countA, imgA, PAD, PAD, parts, undefined, true);
    }

    // Operator
    const sym = op === 'add' ? '+' : '−';
    parts.push(`<text x="${PAD + realWA + OP_W / 2}" y="${opY}" dominant-baseline="central" text-anchor="middle" font-size="30" font-weight="700" font-family="${FONT}" fill="#374151">${sym}</text>`);

    // Group B — top-aligned
    if (numB) {
      parts.push(`<text x="${PAD + realWA + OP_W}" y="${opY}" dominant-baseline="central" text-anchor="start" font-size="${fs}" font-weight="700" font-family="${FONT}" fill="#1F2937">${countB}</text>`);
    } else {
      renderGroup(countB, imgB, PAD + realWA + OP_W, PAD, parts, crossedB ? 0 : undefined, true);
    }

    // Optional = ?
    if (showEq) {
      const eqX = PAD + realWA + OP_W + realWB;
      parts.push(`<text x="${eqX + 22}" y="${opY}" dominant-baseline="central" text-anchor="middle" font-size="30" font-weight="700" font-family="${FONT}" fill="#374151">=</text>`);
      parts.push(`<text x="${eqX + 65}" y="${opY}" dominant-baseline="central" text-anchor="middle" font-size="${fs}" font-weight="700" font-family="${FONT}" fill="#1F2937">?</text>`);
    }

    return { svgW, svgH };
  }

  // ── Build SVG ─────────────────────────────────────────────────────────────
  const parts = [];
  let svgW, svgH;

  if (mode === 'count') {
    const {w, h} = renderGroup(countA, imgA, PAD, PAD, parts);
    svgW = w + PAD * 2; svgH = h + PAD * 2;

  } else if (mode === 'addsub') {
    if (op === 'sub' && subMode === 'total') {
      const {w, h} = renderGroup(countA, imgA, PAD, PAD, parts);
      svgW = w + PAD * 2; svgH = h + PAD * 2;
    } else if (op === 'sub' && subMode === 'crossed') {
      const crossFrom = Math.max(0, countA - countB);
      const {w, h} = renderGroup(countA, imgA, PAD, PAD, parts, crossFrom);
      svgW = w + PAD * 2; svgH = h + PAD * 2;
    } else if (display === 'frame') {
      // Combined frame for addsub: A items first, then B items, side-by-side frames when > 10
      const total = countA + countB;
      const fGap = 16;
      const numFrames = Math.ceil(Math.max(1, total) / F_PER);
      svgW = PAD + numFrames * (FW + fGap) - fGap + PAD;
      svgH = FH + PAD * 2;
      const GL = 1.5, GC = '#374151', lh = GL / 2;
      for (let f = 0; f < numFrames; f++) {
        const fx = PAD + f * (FW + fGap);
        const fy = PAD;
        parts.push(`<rect x="${fx}" y="${fy}" width="${FW}" height="${FH}" fill="#fff"/>`);
        const fStart = f * F_PER, fCount = Math.min(total - fStart, F_PER);
        for (let i = 0; i < fCount; i++) {
          const gi = fStart + i, col = i % F_COLS, row = Math.floor(i / F_COLS);
          const cx = fx + col * FS + FS / 2;
          const cy = fy + row * FS + FS / 2;
          parts.push(renderItem(gi < countA ? imgA : imgB, cx, cy, gi >= countA && op === 'sub', RF));
        }
        const la = `stroke="${GC}" stroke-width="${GL}" stroke-linecap="square"`;
        for (let col = 0; col <= F_COLS; col++) {
          const x = col === 0 ? fx + lh : col === F_COLS ? fx + FW - lh : fx + col * FS;
          parts.push(`<line x1="${x}" y1="${fy + lh}" x2="${x}" y2="${fy + FH - lh}" ${la}/>`);
        }
        for (let row = 0; row <= F_ROWS; row++) {
          const y = row === 0 ? fy + lh : row === F_ROWS ? fy + FH - lh : fy + row * FS;
          parts.push(`<line x1="${fx + lh}" y1="${y}" x2="${fx + FW - lh}" y2="${y}" ${la}/>`);
        }
      }
    } else {
      const {svgW: w2, svgH: h2} = renderTwoGroups(parts, false);
      svgW = w2; svgH = h2;
    }

  } else if (mode === 'multiply') {
    const count = mrows * mcols;
    const {w, h} = arrayBox(count, mcols);
    svgW = w + PAD * 2; svgH = h + PAD * 2;
    arrayPts(count, mcols, PAD, PAD).forEach(({x, y}) => parts.push(renderItem(imgA, x, y)));
  }

  const defsBlock = defs.length ? `<defs>${defs.join('')}</defs>` : '';
  // count+array|clustered: fill canvas width. Everything else: natural size, centred.
  // Frame mode always centres (align setting doesn't apply to discrete frames).
  const useNaturalSize = true; // always use explicit px width so imgScale takes effect
  const centre = display === 'frame' || align !== 'left';
  const svgStyle = useNaturalSize
    ? `display:block;${centre ? 'margin:0 auto;' : ''}width:${Math.ceil(svgW)}px;max-width:100%;background:#fff;border-radius:4px`
    : 'display:block;min-width:100%;background:#fff;border-radius:4px';
  return `<svg viewBox="0 0 ${Math.ceil(svgW)} ${Math.ceil(svgH)}" xmlns="http://www.w3.org/2000/svg" style="${svgStyle}">${defsBlock}${parts.join('')}</svg>`;
}
